{
  "name": "FocusTrack - Learning & Task System",
  "description": "A dual-user productivity dashboard for long-term learning streaks, task management, and progress tracking for Veerababu and Dinesh.",
  "requestFramePermissions": []
}

export enum TaskCategory {
  NEW_LEARNING = 'New Learning',
  REVISION = 'Revision',
  BREAK = 'Break'
}

export interface Task {
  id: string;
  userId: string;
  date: string; // ISO format (YYYY-MM-DD)
  title: string;
  category: TaskCategory;
  topic: string;
  duration: number; // in minutes
  completed: boolean;
  completionPercentage: number;
  startTime: string; // HH:mm
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  streak: number;
}

export interface DailyStats {
  date: string;
  completedHours: number;
  plannedHours: number;
  completionRate: number;
}

export interface AISuggestion {
  title: string;
  topic: string;
  duration: number;
  category: TaskCategory;
  reason: string;
}

import React from 'react';
import { User, TaskCategory } from './types';

export const USERS: User[] = [
  {
    id: 'veerababu',
    name: 'Veerababu',
    avatar: 'https://picsum.photos/seed/veera/200',
    streak: 0
  },
  {
    id: 'dinesh',
    name: 'Dinesh',
    avatar: 'https://picsum.photos/seed/dinesh/200',
    streak: 0
  }
];

export const TOPICS = {
  [TaskCategory.NEW_LEARNING]: ['Java', 'Python', 'ML', 'AI', 'System Design', 'Algorithms'],
  [TaskCategory.REVISION]: ['Full Stack', 'React', 'TypeScript', 'Node.js', 'PostgreSQL', 'Tailwind'],
  [TaskCategory.BREAK]: ['Short Break', 'Long Break', 'Exercise', 'Lunch']
};

export const TARGET_DAILY_HOURS = 6;

import { GoogleGenAI, Type } from "@google/genai";
import { TaskCategory, AISuggestion } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getTaskSuggestions = async (
  userName: string,
  existingTopics: string[]
): Promise<AISuggestion[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Suggest 3 learning tasks for ${userName}. Current focused topics: ${existingTopics.join(', ')}. 
      Ensure tasks fit into a 6-hour daily schedule.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              topic: { type: Type.STRING },
              duration: { type: Type.NUMBER, description: 'Duration in minutes' },
              category: { 
                type: Type.STRING, 
                enum: [TaskCategory.NEW_LEARNING, TaskCategory.REVISION] 
              },
              reason: { type: Type.STRING }
            },
            required: ['title', 'topic', 'duration', 'category', 'reason']
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text) as AISuggestion[];
  } catch (error) {
    console.error("Error fetching AI suggestions:", error);
    return [];
  }
};

import React from 'react';

interface CircularProgressProps {
  percentage: number;
  size?: number;
  strokeWidth?: number;
  color?: string;
}

const CircularProgress: React.FC<CircularProgressProps> = ({
  percentage,
  size = 120,
  strokeWidth = 10,
  color = 'stroke-indigo-600'
}) => {
  const radius = (size - strokeWidth) / 2;
  const circumference = radius * 2 * Math.PI;
  const offset = circumference - (percentage / 100) * circumference;

  return (
    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
      <svg width={size} height={size} className="transform -rotate-90">
        {/* Background circle */}
        <circle
          className="stroke-slate-200"
          strokeWidth={strokeWidth}
          fill="transparent"
          r={radius}
          cx={size / 2}
          cy={size / 2}
        />
        {/* Progress circle */}
        <circle
          className={`${color} transition-all duration-500 ease-out`}
          strokeWidth={strokeWidth}
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          strokeLinecap="round"
          fill="transparent"
          r={radius}
          cx={size / 2}
          cy={size / 2}
        />
      </svg>
      <div className="absolute flex flex-col items-center">
        <span className="text-2xl font-bold text-slate-800">{Math.round(percentage)}%</span>
      </div>
    </div>
  );
};

export default CircularProgress;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { DailyStats } from '../types';

interface HistoryHeatmapProps {
  stats: DailyStats[];
}

const HistoryHeatmap: React.FC<HistoryHeatmapProps> = ({ stats }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || stats.length === 0) return;

    const margin = { top: 20, right: 10, bottom: 20, left: 30 };
    const width = 600 - margin.left - margin.right;
    const height = 150 - margin.top - margin.bottom;

    d3.select(svgRef.current).selectAll("*").remove();

    const svg = d3.select(svgRef.current)
      .attr("viewBox", `0 0 ${width + margin.left + margin.right} ${height + margin.top + margin.bottom}`)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const cellSize = 14;
    const colorScale = d3.scaleSequential(d3.interpolateGreens)
      .domain([0, 100]);

    // Simple implementation: show last 30 days
    const last30Days = [...Array(30)].map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (29 - i));
      const dateStr = d.toISOString().split('T')[0];
      const stat = stats.find(s => s.date === dateStr);
      return {
        date: dateStr,
        value: stat ? stat.completionRate : 0,
        day: d.getDay(),
        week: Math.floor(i / 7)
      };
    });

    svg.selectAll("rect")
      .data(last30Days)
      .enter()
      .append("rect")
      .attr("width", cellSize)
      .attr("height", cellSize)
      .attr("x", (d, i) => Math.floor(i / 7) * (cellSize + 4))
      .attr("y", (d) => d.day * (cellSize + 4))
      .attr("fill", (d) => d.value === 0 ? "#f1f5f9" : colorScale(d.value))
      .attr("rx", 2)
      .append("title")
      .text(d => `${d.date}: ${Math.round(d.value)}%`);

    // Add labels
    const days = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
    svg.selectAll(".dayLabel")
      .data(days)
      .enter()
      .append("text")
      .text(d => d)
      .attr("x", -20)
      .attr("y", (d, i) => i * (cellSize + 4) + 11)
      .attr("font-size", "10px")
      .attr("fill", "#64748b");

  }, [stats]);

  return (
    <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 overflow-x-auto">
      <h3 className="text-sm font-semibold text-slate-600 mb-4 uppercase tracking-wider">30-Day Activity</h3>
      <svg ref={svgRef} className="w-full h-auto max-w-[600px]"></svg>
    </div>
  );
};

export default HistoryHeatmap;

import React, { useState, useEffect } from 'react';
import { Task, TaskCategory } from '../types';
import { TOPICS } from '../constants';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Partial<Task>) => void;
  editTask?: Task | null;
}

const TaskModal: React.FC<TaskModalProps> = ({ isOpen, onClose, onSave, editTask }) => {
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<TaskCategory>(TaskCategory.NEW_LEARNING);
  const [topic, setTopic] = useState('');
  const [duration, setDuration] = useState(60);
  const [startTime, setStartTime] = useState('09:00');

  useEffect(() => {
    if (editTask) {
      setTitle(editTask.title);
      setCategory(editTask.category);
      setTopic(editTask.topic);
      setDuration(editTask.duration);
      setStartTime(editTask.startTime);
    } else {
      setTitle('');
      setCategory(TaskCategory.NEW_LEARNING);
      setTopic(TOPICS[TaskCategory.NEW_LEARNING][0]);
      setDuration(60);
      setStartTime('09:00');
    }
  }, [editTask, isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
          <h2 className="text-lg font-bold text-slate-800">{editTask ? 'Edit Task' : 'Add New Task'}</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        <div className="p-6 space-y-4">
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Task Title</label>
            <input 
              type="text" 
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
              placeholder="e.g. Study Concurrency in Java"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
              <select 
                value={category}
                onChange={(e) => {
                  const newCat = e.target.value as TaskCategory;
                  setCategory(newCat);
                  setTopic(TOPICS[newCat][0] || '');
                }}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {Object.values(TaskCategory).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Topic</label>
              <select 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {TOPICS[category].map(t => (
                  <option key={t} value={t}>{t}</option>
                ))}
                <option value="Custom">Custom Topic</option>
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duration (Min)</label>
              <input 
                type="number" 
                value={duration}
                onChange={(e) => setDuration(parseInt(e.target.value) || 0)}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                min="5"
                step="5"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Start Time</label>
              <input 
                type="time" 
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>
        </div>

        <div className="px-6 py-4 bg-slate-50 flex justify-end gap-3">
          <button 
            onClick={onClose}
            className="px-4 py-2 rounded-lg text-slate-600 hover:bg-slate-200 transition-colors font-medium"
          >
            Cancel
          </button>
          <button 
            onClick={() => onSave({ title, category, topic, duration, startTime })}
            className="px-6 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 shadow-md shadow-indigo-200 transition-all font-bold"
          >
            Save Task
          </button>
        </div>
      </div>
    </div>
  );
};

export default TaskModal;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Task, DailyStats, TaskCategory, AISuggestion } from './types';
import { USERS, TARGET_DAILY_HOURS } from './constants';
import CircularProgress from './components/CircularProgress';
import TaskModal from './components/TaskModal';
import HistoryHeatmap from './components/HistoryHeatmap';
import { getTaskSuggestions } from './geminiService';

const App: React.FC = () => {
  const [activeUserId, setActiveUserId] = useState<string>(USERS[0].id);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [aiSuggestions, setAiSuggestions] = useState<AISuggestion[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const currentUser = useMemo(() => USERS.find(u => u.id === activeUserId)!, [activeUserId]);
  const today = new Date().toISOString().split('T')[0];

  // Persistence
  useEffect(() => {
    const savedTasks = localStorage.getItem('focus_tasks');
    if (savedTasks) {
      setTasks(JSON.parse(savedTasks));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('focus_tasks', JSON.stringify(tasks));
  }, [tasks]);

  const userTasksToday = useMemo(() => 
    tasks.filter(t => t.userId === activeUserId && t.date === today)
    .sort((a, b) => a.startTime.localeCompare(b.startTime))
  , [tasks, activeUserId, today]);

  const stats = useMemo(() => {
    const plannedMins = userTasksToday.reduce((acc, t) => acc + t.duration, 0);
    const completedMins = userTasksToday.reduce((acc, t) => acc + (t.completed ? t.duration : 0), 0);
    const completionPercentage = plannedMins > 0 ? (completedMins / plannedMins) * 100 : 0;

    return {
      plannedMins,
      completedMins,
      completionPercentage,
      plannedHours: (plannedMins / 60).toFixed(1),
      completedHours: (completedMins / 60).toFixed(1),
      targetHours: TARGET_DAILY_HOURS
    };
  }, [userTasksToday]);

  const historyStats = useMemo(() => {
    const userHistory = tasks.filter(t => t.userId === activeUserId);
    const dateGroups = userHistory.reduce((acc, task) => {
      if (!acc[task.date]) acc[task.date] = [];
      acc[task.date].push(task);
      return acc;
    }, {} as Record<string, Task[]>);

    return Object.entries(dateGroups).map(([date, dayTasks]) => {
      const pMins = dayTasks.reduce((acc, t) => acc + t.duration, 0);
      const cMins = dayTasks.reduce((acc, t) => acc + (t.completed ? t.duration : 0), 0);
      return {
        date,
        plannedHours: pMins / 60,
        completedHours: cMins / 60,
        completionRate: pMins > 0 ? (cMins / pMins) * 100 : 0
      };
    });
  }, [tasks, activeUserId]);

  const currentStreak = useMemo(() => {
    const sortedDates = historyStats
      .filter(s => s.completionRate > 50) // Threshold for streak
      .map(s => s.date)
      .sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

    let streak = 0;
    let checkDate = new Date();

    // Simple streak logic: check consecutive days including today or yesterday
    for (let i = 0; i < sortedDates.length; i++) {
      const dateStr = checkDate.toISOString().split('T')[0];
      if (sortedDates.includes(dateStr)) {
        streak++;
        checkDate.setDate(checkDate.getDate() - 1);
      } else if (i === 0) {
        // If today is not completed, check yesterday to keep streak alive
        checkDate.setDate(checkDate.getDate() - 1);
        const yestStr = checkDate.toISOString().split('T')[0];
        if (sortedDates.includes(yestStr)) {
          streak++;
          checkDate.setDate(checkDate.getDate() - 1);
        } else {
          break;
        }
      } else {
        break;
      }
    }
    return streak;
  }, [historyStats]);

  const handleAddTask = (taskData: Partial<Task>) => {
    if (editingTask) {
      setTasks(prev => prev.map(t => t.id === editingTask.id ? { ...t, ...taskData } as Task : t));
    } else {
      const newTask: Task = {
        id: crypto.randomUUID(),
        userId: activeUserId,
        date: today,
        completed: false,
        completionPercentage: 0,
        ...taskData as any
      };
      setTasks(prev => [...prev, newTask]);
    }
    setIsModalOpen(false);
    setEditingTask(null);
  };

  const toggleTask = (taskId: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (taskId: string) => {
    if (confirm("Delete this task?")) {
      setTasks(prev => prev.filter(t => t.id !== taskId));
    }
  };

  const handleAiSuggest = async () => {
    setIsAiLoading(true);
    const existingTopics = Array.from(new Set(userTasksToday.map(t => t.topic)));
    const suggestions = await getTaskSuggestions(currentUser.name, existingTopics);
    setAiSuggestions(suggestions);
    setIsAiLoading(false);
  };

  const addAiTask = (suggestion: AISuggestion) => {
    const newTask: Task = {
      id: crypto.randomUUID(),
      userId: activeUserId,
      date: today,
      title: suggestion.title,
      category: suggestion.category,
      topic: suggestion.topic,
      duration: suggestion.duration,
      completed: false,
      completionPercentage: 0,
      startTime: "10:00" // Default start time for AI suggested tasks
    };
    setTasks(prev => [...prev, newTask]);
    setAiSuggestions(prev => prev.filter(s => s !== suggestion));
  };

  return (
    <div className="min-h-screen pb-20 max-w-6xl mx-auto px-4 sm:px-6">
      {/* Header & Tabs */}
      <header className="sticky top-0 z-40 bg-slate-50/80 backdrop-blur-md pt-6 pb-4 border-b border-slate-200">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex bg-slate-200 p-1 rounded-xl shadow-inner">
            {USERS.map(user => (
              <button
                key={user.id}
                onClick={() => setActiveUserId(user.id)}
                className={`flex items-center gap-3 px-6 py-2 rounded-lg transition-all font-bold ${
                  activeUserId === user.id 
                  ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' 
                  : 'text-slate-600 hover:text-slate-800'
                }`}
              >
                <img src={user.avatar} className="w-6 h-6 rounded-full ring-2 ring-indigo-50" alt="" />
                {user.name}
              </button>
            ))}
          </div>
          <div className="text-right">
            <h1 className="text-lg font-bold text-slate-800">{new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</h1>
            <p className="text-sm text-slate-500 font-medium">Focused Learning Mode</p>
          </div>
        </div>
      </header>

      <main className="mt-8 grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Stats & Streaks */}
        <div className="space-y-6">
          <div className="glass-card p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center">
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-6">Daily Completion</h2>
            <CircularProgress percentage={stats.completionRate} size={160} />
            <div className="mt-8 grid grid-cols-2 gap-8 w-full">
              <div className="text-center">
                <span className="block text-2xl font-black text-slate-800">{stats.completedHours}h</span>
                <span className="text-xs font-bold text-slate-400 uppercase">Actual</span>
              </div>
              <div className="text-center border-l border-slate-100">
                <span className="block text-2xl font-black text-slate-800">{stats.plannedHours}h</span>
                <span className="text-xs font-bold text-slate-400 uppercase">Planned</span>
              </div>
            </div>
            <div className="mt-6 pt-6 border-t border-slate-100 w-full flex justify-between items-center">
              <span className="text-slate-600 font-bold flex items-center gap-2">
                <span className="text-orange-500">🔥</span> {currentStreak} Day Streak
              </span>
              <span className="text-xs font-bold bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full">Goal: 6h/day</span>
            </div>
          </div>

          <HistoryHeatmap stats={historyStats} />

          <div className="bg-indigo-600 p-6 rounded-2xl shadow-lg shadow-indigo-200 text-white relative overflow-hidden group">
            <div className="relative z-10">
              <h3 className="font-bold text-lg">AI Tutor Suggestions</h3>
              <p className="text-indigo-100 text-sm mt-1">Generate optimized learning tasks based on your progress.</p>
              <button 
                onClick={handleAiSuggest}
                disabled={isAiLoading}
                className="mt-4 w-full bg-white text-indigo-600 py-2.5 rounded-xl font-black text-sm shadow-md active:scale-95 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isAiLoading ? (
                  <svg className="animate-spin h-5 w-5 mr-3" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : '🪄 Suggest Tasks'}
              </button>
            </div>
            <div className="absolute -right-4 -bottom-4 opacity-10 scale-150 rotate-12 transition-transform group-hover:rotate-0">
               <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L14.4 9.6H22L15.8 14.2L18.2 21.8L12 17.2L5.8 21.8L8.2 14.2L2 9.6H9.6L12 2Z"/></svg>
            </div>
          </div>

          {aiSuggestions.length > 0 && (
            <div className="space-y-3">
              <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">Suggested for today</h3>
              {aiSuggestions.map((s, idx) => (
                <div key={idx} className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm flex justify-between items-start gap-4 animate-in slide-in-from-right-4 duration-300">
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-bold px-2 py-0.5 rounded-md bg-indigo-50 text-indigo-600">{s.topic}</span>
                      <span className="text-xs text-slate-400 font-medium">{s.duration} min</span>
                    </div>
                    <h4 className="font-bold text-slate-800 mt-1">{s.title}</h4>
                    <p className="text-xs text-slate-500 mt-1 line-clamp-2">{s.reason}</p>
                  </div>
                  <button 
                    onClick={() => addAiTask(s)}
                    className="p-2 rounded-lg bg-indigo-50 text-indigo-600 hover:bg-indigo-600 hover:text-white transition-colors"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"/></svg>
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Right Columns: Task List / Timeline */}
        <div className="lg:col-span-2 space-y-4">
          <div className="flex justify-between items-center mb-2">
            <h2 className="text-xl font-black text-slate-800">Your Schedule</h2>
            <button 
              onClick={() => { setEditingTask(null); setIsModalOpen(true); }}
